const haberler = [];
const seen = new Set();

// Script ve style etiketlerini temizle
const cleanHtml = html
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<nav[\s\S]*?<\/nav>/gi, '')
  .replace(/<footer[\s\S]*?<\/footer>/gi, '');

// Yöntem 1: data-title veya title özelliği olan linkler
const titleAttrPattern = /href="([^"]+)"[^>]*(?:data-title|title)="([^"]{15,200})"/gi;
let match;
while ((match = titleAttrPattern.exec(cleanHtml)) !== null) {
  let url = match[1];
  const text = match[2].trim().replace(/\s+/g, ' ');
  if (url.startsWith('/')) url = 'https://www.mynet.com' + url;
  if (!url.includes('mynet.com')) continue;
  if (!seen.has(url) && text.length >= 15) {
    seen.add(url);
    haberler.push({ baslik: text, link: url });
  }
}

// Yöntem 2: Mynet haber URL pattern'i olan linkler + içindeki text
const linkTextPattern = /href="((?:https?:\/\/(?:www\.)?mynet\.com)?\/[a-zA-Z0-9\-\/]+(?:haber|magazin|galeri)[a-zA-Z0-9\-\/]*\.html)"[^>]*>\s*([^<]{15,200})/gi;
while ((match = linkTextPattern.exec(cleanHtml)) !== null) {
  let url = match[1];
  const text = match[2].trim().replace(/\s+/g, ' ');
  if (url.startsWith('/')) url = 'https://www.mynet.com' + url;
  if (!seen.has(url) && text.length >= 15 && !/^\s*$/.test(text)) {
    seen.add(url);
    haberler.push({ baslik: text, link: url });
  }
}

// Yöntem 3: Article/section içindeki a etiketleri
const articlePattern = /<(?:article|section|div)[^>]*class="[^"]*(?:haber|news|card|item|post)[^"]*"[^>]*>[\s\S]*?<a[^>]+href="([^"]+)"[^>]*>\s*([^<]{15,150})\s*<\/a>/gi;
while ((match = articlePattern.exec(cleanHtml)) !== null) {
  let url = match[1];
  const text = match[2].trim().replace(/\s+/g, ' ');
  if (url.startsWith('/')) url = 'https://www.mynet.com' + url;
  if (!url.startsWith('http')) continue;
  if (!seen.has(url) && text.length >= 15) {
    seen.add(url);
    haberler.push({ baslik: text, link: url });
  }
}

