// 1. Veri Kaynağını Bul
const root = items[0].json;
let rawText = "";

// Veri nerede saklanıyor? (Senin loglarına göre content[0].text içinde)
if (root.content && Array.isArray(root.content) && root.content[0] && root.content[0].text) {
    rawText = root.content[0].text;
} else if (root.output) {
    // Başka modeller için yedek
    rawText = typeof root.output === 'string' ? root.output : JSON.stringify(root.output);
} else {
    // Hiçbiri yoksa her şeyi metne çevir
    rawText = JSON.stringify(root);
}

// 2. AĞIR TEMİZLİK (Sorunu çözen kısım burası)
// Metni dümdüz yapıyoruz: Yeni satırları (\n) sil, ters slashleri (\) sil.
// Böylece regex hata yapamaz.
const cleanOneLine = rawText
    .replace(/\\n/g, " ")   // \n işaretlerini boşluk yap
    .replace(/\n/g, " ")    // Gerçek enter'ları boşluk yap
    .replace(/\\"/g, '"')   // \" işaretlerini düz tırnak yap
    .replace(/\\/g, "")     // Geriye kalan tüm ters çizgileri sil
    .replace(/\s+/g, " ");  // Fazla boşlukları teke indir

// 3. BASİT ARAMA (Artık metin dümdüz olduğu için basit regex çalışır)
// "key": "value" yapısını arıyoruz.

// Caption: "caption" kelimesinden sonra gelen tırnak içindeki yazıyı al
const captionMatch = cleanOneLine.match(/"caption"\s*:\s*"([^"]+)"/i);

// Score: "score" kelimesinden sonra gelen tırnak içindeki yazıyı al
const scoreMatch = cleanOneLine.match(/"score"\s*:\s*"([^"]+)"/i);

// Opponent: "opponent" kelimesinden sonra gelen tırnak içindeki yazıyı al
const opponentMatch = cleanOneLine.match(/"opponent"\s*:\s*"([^"]+)"/i);

// 4. Sonuçları Ver
return [{
    json: {
        // Eğer bulamazsa, temizlenmiş metnin başını göster ki hatayı görelim
        my_caption: captionMatch ? captionMatch[1] : ("HATA: Bulunamadı. Metin: " + cleanOneLine.substring(0, 100)),
        my_opponent: opponentMatch ? opponentMatch[1] : "Rakip Takım",
        my_score: scoreMatch ? scoreMatch[1] : "0-0"
    }
}];

